def perceive(data):
    if isinstance(data, dict):
        src = {}
        for k, v in data.items():
            src[str(k).strip().lower()] = v
    else:
        src = {}
        for line in str(data).splitlines():
            if ":" in line:
                k, v = line.split(":", 1)
                src[k.strip().lower()] = v.strip()
    out = {}
    subject = src.get("subject") or src.get("text") or src.get("request")
    if subject:
        out["request_text"] = str(subject)
    records = src.get("records")
    if records is not None:
        try:
            out["responsive_records"] = int(records)
        except (ValueError, TypeError):
            pass
    pages = src.get("pages")
    if pages is not None:
        try:
            out["pages_total"] = int(pages)
        except (ValueError, TypeError):
            pass
    return out
